public double evaluate(final double[] values, final double[] weights, final double mean, final int begin, final int length) {
 if (length == 1) return 0.0;

 double accum = 0.0;
 for (int i = begin; i < begin + length; i++) {
 accum += weights[i] * Math.pow(values[i] - mean, 2.0);
 }

 double var = accum / (length - 1.0);
 if (isBiasCorrected) {
 var *= (length / (length - 1.0));
 }

 return var;
}
